            HWREG(MEMCFG_BASE + MEMCFG_O_ROM_LOCK)           |=
                  (MEMCFG_TESTLOCK_KEY | (MEMCFG_SECT_NUM_MASK & memSections));
            HWREG(MEMCFG_BASE + MEMCFG_O_PERI_MEM_TEST_LOCK) |=
                  (MEMCFG_TESTLOCK_KEY | (MEMCFG_SECT_NUM_MASK & memSections));
            break;

        default:
            //
            // Do nothing. Invalid ramSections. Make sure you aren't OR-ing
