            //
            HWREG(MEMCFG_BASE + MEMCFG_O_DXRAMTEST_LOCK)   =
                 HWREG(MEMCFG_BASE + MEMCFG_O_DXRAMTEST_LOCK)   |
                 (MEMCFG_TESTLOCK_KEY | ~(MEMCFG_SECT_NUM_MASK & memSections));
            HWREG(MEMCFG_BASE + MEMCFG_O_LSXRAMTEST_LOCK)  =
                 HWREG(MEMCFG_BASE + MEMCFG_O_LSXRAMTEST_LOCK)  |
                 (MEMCFG_TESTLOCK_KEY | ~(MEMCFG_SECT_NUM_MASK & memSections));
